+import Foundation
+
+enum ShortcutCaptureEvent: Equatable, Sendable {
+    case keyPressed(HotkeyKey)
+    case keyReleased(HotkeyKey)
+}
+
+final class ShortcutCaptureStateMachine {
+    private(set) var pressedKeys: Set<HotkeyKey> = []
+    private(set) var capturedKeys: Set<HotkeyKey> = []
+
+    func process(_ event: ShortcutCaptureEvent) -> HotkeyChord? {
+        switch event {
+        case let .keyPressed(key):
+            pressedKeys.insert(key)
+            capturedKeys.insert(key)
+            return nil
+        case let .keyReleased(key):
+            pressedKeys.remove(key)
+            guard pressedKeys.isEmpty, !capturedKeys.isEmpty else {
+                return nil
+            }
+
+            let chord = try? HotkeyChord(keys: capturedKeys)
+            reset()
+            return chord
+        }
+    }
+
+    func reset() {
+        pressedKeys.removeAll()
+        capturedKeys.removeAll()
+    }
+}

